def _init_mitsuba() -> str:
    try:
        mi.set_variant("cuda_ad_rgb")
        return "cuda_ad_rgb"
    except Exception:
        mi.set_variant("llvm_ad_rgb")
        return "llvm_ad_rgb"

VARIANT = _init_mitsuba()
print(f"Mitsuba variant: {VARIANT}")

